module bubble_sort (
    input [15:0] data_in, // 4 elements of 4 bits each
    output reg [15:0] data_out // sorted 4 elements of 4 bits each
);
    integer i, j;
    reg [3:0] obf_temp [0:3]; // temporary storage for sorting

    always @* begin
        // Load input data into temporary array
        for (i = 0; i < 4; i = i + 1) begin
            obf_temp[i] = data_in[i*4 +: 4];
        end

        // Bubble sort algorithm
        for (i = 0; i < 3; i = i + 1) begin
            for (j = 0; j < 3 - i; j = j + 1) begin
                if (obf_temp[j] > obf_temp[j + 1]) begin
                    // Swap
                    obf_temp[j] = obf_temp[j] ^ obf_temp[j + 1];
                    obf_temp[j + 1] = obf_temp[j] ^ obf_temp[j + 1];
                    obf_temp[j] = obf_temp[j] ^ obf_temp[j + 1];
                end
            end
        end

        // Load sorted data into output
        data_out = {obf_temp[3], obf_temp[2], obf_temp[1], obf_temp[0]};
    end
endmodule
